class RegisterFormModel { final String name; final String email; final String password; final String confirmPassword; const RegisterFormModel({this.name = '', this.email = '', this.password = '', this.confirmPassword = ''}); bool get isValid => name.length >= 2 && email.contains('@') && password.length >= 8 && password == confirmPassword; RegisterFormModel copyWith({String? name, String? email, String? password, String? confirmPassword}) => RegisterFormModel(name: name ?? this.name, email: email ?? this.email, password: password ?? this.password, confirmPassword: confirmPassword ?? this.confirmPassword); }